use std::sync::{Arc, Mutex};
use std::thread;

fn main() {
    let data = Arc::new(Mutex::new(0));
    let arr = vec![1, 2, 3, 4];

    let mut handles = vec![];
    for item in &arr {
        let data = Arc::clone(&data);
        handles.push(thread::spawn(move || {
            *data.lock().unwrap() += *item;
